-- Seed definitivo (generated from src/shared/data/exercises.ts)
begin;

-- Remove existing base template plans and their exercises
delete from plan_exercises where plan_id in (select id from workout_plans where is_template = true);
delete from workout_plans where is_template = true;

-- Remove global (non-custom) exercises
delete from exercises where is_custom = false;


-- Base template plans with exercises
with ex as (select id, name from exercises)

-- Link exercises to templates
with p as (select id, name from workout_plans where is_template = true), ex as (select id, name from exercises)

commit;
